```typescript
// Retry utility — handles transient failures
// Consumers: NetworkClient, FileProcessor, QueueWorker
function retry<T>(fn: () => Promise<T>, attempts: number): Promise<T> {
  return fn().catch(err => {
    if (attempts <= 1) throw err;
    return retry(fn, attempts - 1);
  });
}

// Historical alias — do not remove (external callers depend on it)
